71	
72	/**
73	 * RedesignedWorkspace — composition route for the §11–§17 chrome.
74	 *
75	 * Mounted at `/redesign`. Reads from `useBimStore` (same data as the
76	 * legacy `Workspace.tsx`) so engineers can A/B compare the two surfaces
77	 * without forking state. The canvas slot reuses the existing `Viewport`
78	 * / `PlanCanvas` components — only the chrome (TopBar / LeftRail /
79	 * Inspector / StatusBar / ToolPalette) is new.
80	 *
81	 * Spec sections wired here: §7 modes (1–7), §8 layout grid, §11 TopBar,
82	 * §12 Project Browser, §13 Inspector, §16 Tool palette, §17 StatusBar.
83	 */
84	
85	const KNOWN_PLAN_TOOLS = new Set<ToolId>(['select', 'wall', 'door', 'window', 'room', 'dimension']);
86	
87	type LegacyPlanTool =
88	  | 'select'
89	  | 'wall'
90	  | 'door'
91	  | 'window'
92	  | 'room'
93	  | 'room_rectangle'
94	  | 'grid'
95	  | 'dimension';
96	
97	function toolIdToLegacy(tool: ToolId): LegacyPlanTool | null {
98	  if (KNOWN_PLAN_TOOLS.has(tool)) return tool as LegacyPlanTool;
99	  return null;
100	}
101	
102	function legacyToToolId(legacy: LegacyPlanTool): ToolId {
103	  if (legacy === 'room_rectangle') return 'room';
104	  if (legacy === 'grid') return 'select';
105	  return legacy as ToolId;
106	}
107	
108	export function RedesignedWorkspace(): JSX.Element {
109	  const elementsById = useBimStore((s) => s.elementsById);
110	  const hydrateFromSnapshot = useBimStore((s) => s.hydrateFromSnapshot);
111	  const viewerMode = useBimStore((s) => s.viewerMode);
112	  const setViewerMode = useBimStore((s) => s.setViewerMode);
113	  const planTool = useBimStore((s) => s.planTool);
114	  const setPlanTool = useBimStore((s) => s.setPlanTool);
115	  const selectedId = useBimStore((s) => s.selectedId);
116	  const select = useBimStore((s) => s.select);
117	  const activeLevelId = useBimStore((s) => s.activeLevelId);
118	  const setActiveLevelId = useBimStore((s) => s.setActiveLevelId);
119	  const planHudMm = useBimStore((s) => s.planHudMm);
120	
121	  const [mode, setMode] = useState<WorkspaceMode>(() =>
122	    viewerMode === 'orbit_3d' ? '3d' : 'plan',
123	  );
124	  const [theme, setTheme] = useState<Theme>(() => (getCurrentTheme() as Theme) ?? 'light');
125	  const [paletteOpen, setPaletteOpen] = useState(false);
126	  const [cheatsheetOpen, setCheatsheetOpen] = useState(false);
127	  const [recentCommandIds, setRecentCommandIds] = useState<string[]>([]);
128	  const [tourOpen, setTourOpen] = useState<boolean>(() => !readOnboardingProgress().completed);
129	  const [seedLoading, setSeedLoading] = useState(false);
130	  const [seedError, setSeedError] = useState<string | null>(null);
131	  const [projectMenuOpen, setProjectMenuOpen] = useState(false);
132	  const [recentProjects, setRecentProjects] = useState<ProjectMenuItemRecent[]>(() =>
133	    readRecentProjects().map((r) => ({ id: r.id, label: r.label })),
134	  );
135	  const projectNameRef = useRef<HTMLButtonElement | null>(null);
136	  const planCameraHandleRef = useRef<PlanCameraHandle | null>(null);
137	  const [tabsState, setTabsState] = useState<TabsState>(() => readPersistedTabs() ?? EMPTY_TABS);
138	
139	  /** Persist tabs on every change (T-06). */
140	  useEffect(() => {
141	    persistTabs(tabsState);
142	  }, [tabsState]);
143	
144	  /* ── Tab helpers (§11.3) ──────────────────────────────────────────── */
145	  const activeTab: ViewTab | null = useMemo(
146	    () =>
147	      tabsState.activeId ? tabsState.tabs.find((t) => t.id === tabsState.activeId) ?? null : null,
148	    [tabsState],
149	  );
150	
151	  const handleTabActivate = useCallback(
152	    (id: string) => {
153	      let pendingPlanCamera: ViewportSnapshot['planCamera'] | undefined;
154	
155	      setTabsState((s) => {
156	        if (s.activeId === id) return s;
157	        // Snapshot the outgoing tab's viewport state so it can be restored
158	        // when the user comes back. T-07.
159	        let snapshotted = s;
160	        if (s.activeId) {
161	          const outgoing = s.tabs.find((x) => x.id === s.activeId);
162	          if (outgoing) {
163	            if (outgoing.kind === '3d' || outgoing.kind === 'plan-3d') {
164	              const pose = useBimStore.getState().orbitCameraPoseMm;
165	              if (pose) {
166	                snapshotted = snapshotViewport(snapshotted, s.activeId, {
167	                  ...(outgoing.viewportState ?? {}),
168	                  orbitCameraPoseMm: { eyeMm: pose.position, targetMm: pose.target },
169	                });
170	              }
171	            }
172	            // Snapshot the 2D plan camera for plan tabs (T-07 follow-up).
173	            if (outgoing.kind === 'plan' || outgoing.kind === 'plan-3d') {
174	              const planSnap = planCameraHandleRef.current?.getSnapshot();
175	              if (planSnap) {
176	                snapshotted = snapshotViewport(snapshotted, s.activeId, {
177	                  ...(snapshotted.tabs.find((x) => x.id === s.activeId)?.viewportState ?? {}),
178	                  planCamera: planSnap,
179	                });
180	              }
181	            }
182	          }
183	        }
184	        const next = activateTab(snapshotted, id);
185	        const t = next.tabs.find((x) => x.id === id);
186	        if (!t) return next;
187	        // Keep the store's active level in sync with the active tab's target.
188	        if ((t.kind === 'plan' || t.kind === 'plan-3d') && t.targetId) {
189	          setActiveLevelId(t.targetId);
190	        }
191	        // Restore the incoming tab's 3D camera, if it has one.
192	        const restored = t.viewportState?.orbitCameraPoseMm;
193	        if (restored?.eyeMm && restored.targetMm) {
194	          useBimStore.getState().setOrbitCameraFromViewpointMm({
195	            position: restored.eyeMm,
196	            target: restored.targetMm,
197	            up: { xMm: 0, yMm: 1, zMm: 0 },
198	          });
199	        }
200	        // Capture the incoming plan camera for post-setState apply (plan-to-plan case).
201	        if (t.kind === 'plan' || t.kind === 'plan-3d') {
202	          pendingPlanCamera = t.viewportState?.planCamera;
203	        }
204	        return next;
205	      });
206	
207	      // Apply plan camera to the already-mounted PlanCanvas (plan-to-plan switch).
208	      // For 3D→plan switches, initialCamera prop handles restore at mount time.
209	      if (pendingPlanCamera) {
210	        planCameraHandleRef.current?.applySnapshot(pendingPlanCamera);
211	      }
212	    },
213	    [setActiveLevelId],
214	  );
215	
216	  const handleTabClose = useCallback((id: string) => {
217	    setTabsState((s) => closeTab(s, id));
218	  }, []);
219	
220	  const openTabFromElement = useCallback((el: Element) => {
221	    const partial = tabFromElement(el);
222	    if (!partial) return;
223	    setTabsState((s) => openTab(s, partial));
224	  }, []);
225	
226	  /* ── Project menu handlers (T-03) ─────────────────────────────────── */
227	  const handleSaveSnapshot = useCallback(() => {
228	    const st = useBimStore.getState();
229	    if (!st.modelId) {
230	      setSeedError('Nothing to save — bootstrap a model first.');
231	      return;
232	    }
233	    const snap: Snapshot = {
234	      modelId: st.modelId,
235	      revision: st.revision ?? 0,
236	      elements: st.elementsById as unknown as Record<string, unknown>,
237	      violations: [],
238	    };
239	    const payload = buildSnapshotPayload(snap);
240	    downloadSnapshot(payload);
241	    const next = pushRecentProject(payload);
242	    setRecentProjects(next.map((r) => ({ id: r.id, label: r.label })));
243	  }, []);
244	
245	  const handleRestoreSnapshot = useCallback(
246	    async (file: File): Promise<void> => {
247	      try {
248	        const payload = await readSnapshotFile(file);
249	        hydrateFromSnapshot(payload.snapshot);
250	        const next = pushRecentProject(payload);
251	        setRecentProjects(next.map((r) => ({ id: r.id, label: r.label })));
252	      } catch (err) {
253	        setSeedError(err instanceof Error ? err.message : 'Failed to read snapshot');
254	      }
255	    },
256	    [hydrateFromSnapshot],
257	  );
258	
259	  const handlePickRecent = useCallback(
260	    (id: string) => {
261	      const found = findRecentProject(id);
262	      if (!found) return;
263	      hydrateFromSnapshot(found.payload.snapshot);
264	    },
265	    [hydrateFromSnapshot],
266	  );
267	
268	  const handleNewClear = useCallback(() => {
269	    hydrateFromSnapshot({ modelId: 'empty', revision: 0, elements: {}, violations: [] });
270	    setTabsState(EMPTY_TABS);
271	  }, [hydrateFromSnapshot]);
272	
273	  /* ── Semantic command dispatch (from PlanCanvas / Viewport) ────────── */
274	  const onSemanticCommand = useCallback(
275	    async (cmd: Record<string, unknown>): Promise<void> => {
276	      const mid = useBimStore.getState().modelId;
277	      const uid = useBimStore.getState().userId;
278	      if (!mid) return;
279	      try {
280	        const r = await applyCommand(mid, cmd, { userId: uid });
281	        if (r.revision !== undefined) {
282	          hydrateFromSnapshot({
283	            modelId: mid,
284	            revision: r.revision,
285	            elements: r.elements ?? {},
286	            violations: (r.violations ?? []) as Violation[],
287	          });
288	        }
289	      } catch (err) {
290	        // V1: surface the error in seedError-style readout. Full conflict
291	        // queue (legacy `Workspace.tsx`) is out of scope here.
292	        setSeedError(err instanceof Error ? err.message : 'Apply failed');
293	      }
294	    },
295	    [hydrateFromSnapshot],
296	  );
297	
298	  const insertSeedHouse = useCallback(async (): Promise<void> => {
299	    setSeedLoading(true);
300	    setSeedError(null);
301	    try {
302	      const bx = await bootstrap();
303	      const pj = bx.projects as Record<string, unknown>[] | undefined;
304	      const m0 = pj?.[0]?.models as Array<{ id?: unknown }> | undefined;
305	      const mid = m0?.[0]?.id;
306	      if (typeof mid !== 'string') throw new Error('No models — run make seed');
307	      const snapRes = await fetch(`/api/models/${encodeURIComponent(mid)}/snapshot`);
308	      if (!snapRes.ok) throw new Error(`snapshot ${snapRes.status}`);
309	      const snap = (await snapRes.json()) as Snapshot;
310	      hydrateFromSnapshot(snap);
311	    } catch (err) {
312	      setSeedError(err instanceof Error ? err.message : 'Failed to load seed');
313	    } finally {
314	      setSeedLoading(false);
315	    }
316	  }, [hydrateFromSnapshot]);
317	
318	  useEffect(() => {
319	    const isEmpty = Object.keys(elementsById).length === 0;
320	    if (!isEmpty) return;
321	    void insertSeedHouse();
322	    // Run-once bootstrap: re-running is the user's job via the empty-state CTA.
323	    // eslint-disable-next-line react-hooks/exhaustive-deps
324	  }, []);
325	
326	  // After the seed has hydrated, prune any restored tabs whose targets
327	  // no longer exist (e.g. a sheet deleted between sessions). If the
328	  // pruned set is empty, open a default Plan tab on the first level.
329	  // Runs once when the store transitions from empty → non-empty.
